**CODE:**
```tsx
"use client";

import { useEffect, useRef, useState } from "react";
import { X, Calendar, Clock, User, Phone, Scissors, Send } from "lucide-react";
import { SERVICES, BARBERS, TIME_SLOTS, GOOGLE_SCRIPT_URL } from "@/data/site-data";

interface BookingModalProps {
  isOpen: boolean;
  onClose: () => void;
}

type FormStatus = "idle" | "submitting" | "success" | "error";

const EMPTY_FORM = { name: "", phone: "", service: "", barber: "", date: "", time: "" };

function validateForm(data: typeof EMPTY_FORM) {
  const errors: Partial<typeof EMPTY_FORM> = {};
  if (!data.name.trim()) errors.name = "Vui lòng nhập họ và tên";
  else if (data.name.trim().length < 2) errors.name = "Tên phải có ít nhất 2 ký tự";
  if (!data.phone.trim()) errors.phone = "Vui lòng nhập số điện thoại";
  else if (!/^(0|\+84)[0-9]{8,9}$/.test(data.phone.trim()))
    errors.phone = "Số điện thoại không hợp lệ (VD: 0912345678)";
  if (!data.service) errors.service = "Vui lòng chọn dịch vụ";
  if (!data.barber) errors.barber = "Vui lòng chọn thợ cắt tóc";
  if (!data.date) errors.date = "Vui lòng chọn ngày";
  if (!data.time) errors.time = "Vui lòng chọn giờ";
  return errors;
}

export default function BookingModal({ isOpen, onClose }: BookingModalProps) {
  const [formData, setFormData] = useState(EMPTY_FORM);
  const [errors, setErrors] = useState<Partial<typeof EMPTY_FORM>>({});
  const [status, setStatus] = useState<FormStatus>("idle");
  const modalRef = useRef<HTMLDivElement>(null);

  const today = new Date().toISOString().split("T")[0];

  // Reset form and re-focus when modal opens/closes
  useEffect(() => {
    if (!isOpen) {
      setFormData(EMPTY_FORM);
      setErrors({});
      setStatus("idle");
    }
  }, [isOpen]);

  // Focus trap
  useEffect(() => {
    if (!isOpen) return;
    const modal = modalRef.current;
    if (!modal) return;
    const focusable = modal.querySelectorAll<HTMLElement>(
      'button, input, select, [tabindex]:not([tabindex="-1"])'
    );
    const first = focusable[0];
    const last = focusable[focusable.length - 1];

    function onKey(e: KeyboardEvent) {
      if (e.key === "Escape") { handleClose(); return; }
      if (e.key !== "Tab") return;
      if (e.shiftKey) {
        if (document.activeElement === first) { e.preventDefault(); last.focus(); }
      } else {
        if (document.activeElement === last) { e.preventDefault(); first.focus(); }
      }
    }
    document.addEventListener("keydown", onKey);
    first?.focus();
    return () => document.removeEventListener("keydown", onKey);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen]);

  if (!isOpen) return null;

  const handleClose = () => {
    if (status === "submitting") return;
    onClose();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const validationErrors = validateForm(formData);
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }
    setErrors({});
    setStatus("submitting");

    try {
      if (GOOGLE_SCRIPT_URL) {
        await fetch(GOOGLE_SCRIPT_URL, {
          method: "POST",
          mode: "no-cors",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(formData),
        });
      }
      setStatus("success");
      setTimeout(() => {
        setStatus("idle");
        onClose();
      }, 2500);
    } catch {
      setStatus("error");
      setTimeout(() => setStatus("idle"), 3000);
    }
  };

  function setField<K extends keyof typeof EMPTY_FORM>(key: K, value: string) {
    setFormData((prev) => ({ ...prev, [key]: value }));
    if (errors[key]) setErrors((prev) => ({ ...prev, [key]: undefined }));
  }

  return (
    <div
      className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4"
      onClick={handleClose}
      role="dialog"
      aria-modal="true"
      aria-labelledby="booking-modal-title"
    >
      <div
        ref={modalRef}
        className="bg-dark-light rounded-2xl max-w-lg w-full max-h-[90vh] overflow-y-auto border border-white/10"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-5 border-b border-white/10">
          <div>
            <h2
              id="booking-modal-title"
              className="text-xl font-bold text-white uppercase tracking-wider"
              style={{ fontFamily: "Darker Grotesque, sans-serif" }}
            >
              Đặt Lịch <span className="text-gold">Cắt Tóc</span>
            </h2>
            <p className="text-white/50 text-sm mt-1">Chọn dịch vụ và thời gian phù hợp</p>
          </div>
          <button
            onClick={handleClose}
            className="text-white/50 hover:text-white p-1 transition-colors"
            aria-label="Đóng"
          >
            <X size={22} />
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="p-5 space-y-4" noValidate>
          {/* Name */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <User size={14} /> Họ và tên
            </label>
            <input
              type="text"
              value={formData.name}
              onChange={(e) => setField("name", e.target.value)}
              placeholder="Nhập họ tên"
              aria-invalid={!!errors.name}
              className="w-full bg-dark-lighter border border-white/10 rounded-lg px-4 py-2.5 text-white placeholder-white/30 focus:border-gold focus:outline-none transition-colors aria-[invalid=true]:border-red-500"
            />
            {errors.name && <p className="text-red-400 text-xs mt-1" role="alert">{errors.name}</p>}
          </div>

          {/* Phone */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <Phone size={14} /> Số điện thoại
            </label>
            <input
              type="tel"
              value={formData.phone}
              onChange={(e) => setField("phone", e.target.value)}
              placeholder="Nhập số điện thoại"
              aria-invalid={!!errors.phone}
              className="w-full bg-dark-lighter border border-white/10 rounded-lg px-4 py-2.5 text-white placeholder-white/30 focus:border-gold focus:outline-none transition-colors aria-[invalid=true]:border-red-500"
            />
            {errors.phone && <p className="text-red-400 text-xs mt-1" role="alert">{errors.phone}</p>}
          </div>

          {/* Service */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <Scissors size={14} /> Dịch vụ
            </label>
            <select
              value={formData.service}
              onChange={(e) => setField("service", e.target.value)}
              aria-invalid={!!errors.service}
              className="w-full bg-dark-lighter border border-white/10 rounded-lg px-4 py-2.5 text-white focus:border-gold focus:outline-none transition-colors appearance-none cursor-pointer aria-[invalid=true]:border-red-500"
            >
              <option value="" className="bg-dark-lighter">Chọn dịch vụ</option>
              {SERVICES.map((s) => (
                <option key={s.name} value={s.name} className="bg-dark-lighter">
                  {s.name} - {s.price}
                </option>
              ))}
            </select>
            {errors.service && <p className="text-red-400 text-xs mt-1" role="alert">{errors.service}</p>}
          </div>

          {/* Barber */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <User size={14} /> Thợ cắt tóc
            </label>
            <select
              value={formData.barber}
              onChange={(e) => setField("barber", e.target.value)}
              aria-invalid={!!errors.barber}
              className="w-full bg-dark-lighter border border-white/10 rounded-lg px-4 py-2.5 text-white focus:border-gold focus:outline-none transition-colors appearance-none cursor-pointer aria-[invalid=true]:border-red-500"
            >
              <option value="" className="bg-dark-lighter">Chọn thợ cắt tóc</option>
              {BARBERS.map((b) => (
                <option key={b.id} value={b.name} className="bg-dark-lighter">
                  {b.name}
                </option>
              ))}
            </select>
            {errors.barber && <p className="text-red-400 text-xs mt-1" role="alert">{errors.barber}</p>}
          </div>

          {/* Date */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <Calendar size={14} /> Ngày
            </label>
            <input
              type="date"
              min={today}
              value={formData.date}
              onChange={(e) => setField("date", e.target.value)}
              aria-invalid={!!errors.date}
              className="w-full bg-dark-lighter border border-white/10 rounded-lg px-4 py-2.5 text-white focus:border-gold focus:outline-none transition-colors cursor-pointer aria-[invalid=true]:border-red-500"
            />
            {errors.date && <p className="text-red-400 text-xs mt-1" role="alert">{errors.date}</p>}
          </div>

          {/* Time Slots */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <Clock size={14} /> Giờ
            </label>
            <div className="grid grid-cols-4 gap-2">
              {TIME_SLOTS.map((slot) => (
                <button
                  key={slot}
                  type="button"
                  onClick={() => setField("time", slot)}
                  className={`py-2 rounded-lg text-sm font-bold transition-colors cursor-pointer ${
                    formData.time === slot
                      ? "bg-gold text-black"
                      : "bg-dark-lighter border border-white/10 text-white/70 hover:border-gold/30 hover:text-white"
                  }`}
                >
                  {slot}
                </button>
              ))}
            </div>
            {errors.time && <p className="text-red-400 text-xs mt-1" role="alert">{errors.time}</p>}
          </div>

          {/* Submit */}
          <button
            type="submit"
            disabled={status === "submitting"}
            className="w-full bg-gold hover:bg-gold-dark disabled:opacity-50 disabled:cursor-not-allowed text-black font-bold py-3 rounded-lg transition-colors flex items-center justify-center gap-2 mt-2 cursor-pointer"
          >
            {status === "submitting" ? (
              <>
                <div className="w-5 h-5 border-2 border-black/30 border-t-black rounded-full animate-spin" />
                Đang gửi...
              </>
            ) : status === "success" ? (
              "Đặt lịch thành công!"
            ) : status === "error" ? (
              "Có lỗi xảy ra, thử lại"
            ) : (
              <>
                <Send size={18} />
                Xác Nhận Đặt Lịch
              </>
            )}
          </button>
        </form>
      </div>
    </div>
  );
}
```

